var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"허어… 잠깐 생각 정리할 시간 좀 주실래요?","JPN":"はあ……少し考えを整理する時間をください。","ENG":"Uh... Could you give me some time to think about it?","TWN":"呃…可以給我一點時間考慮嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"아니, 진심으로 그런 제안을 하려고 부르셨다는 게 조금 놀라워서요.","JPN":"本当にそんな提案をするためにお呼びになったのだということに少々驚きまして。","ENG":"I'm just... a little surprised you called me to offer something that serious.","TWN":"別誤會，我是真的有點嚇到，沒想到你找我來是因為要提出這個提議。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"한동안 조용하더니 결국 신고식을 치를 날이 왔구나, 하고 긴장한 상태였걸랑요.","JPN":"しばらく大人しかったけど、ついに出戦する日が来てしまったかと緊張していたんです。","ENG":"I was just a little nervous, thinking to myself, \\"It's been quiet for a while, but the day has finally come\\".","TWN":"這陣子都沒什麼動靜，我還以為是什麼大事，害我很緊張呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"뭐라던가, 보이스 피싱이라고 하던가요? 그런 부류의 사기 수법이라거나……","JPN":"なんていうか、オレオレ詐欺っていうんですか？　そのたぐいの詐欺とか……","ENG":"Voice phishing, was it? I thought this was a scam like that...","TWN":"那叫什麼？電話詐騙嗎？就類似那種詐騙手法啦……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"신뢰한다고 말씀하셔도 어깨가 무겁거든요. 그게 진심이든. 빈말이든.","JPN":"信頼しているという言葉も肩の荷が重いです。それが本心でも、お世辞でも。","ENG":"Even if you say you trust me, it's still a heavy burden to bear. Whether they're sincere or empty words.","TWN":"就算你說你信得過我，不管那是真話還假話，我都覺得很有壓力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"중압감 때문에 까딱 잘못하면 지금 당장이라도 기절하겠어요, 솔직히.","JPN":"正直言えば、プレッシャーで下手したら今すぐにでも気を失ってしまいそうです。","ENG":"Honestly, I think I could faint at any moment because of all the pressure.","TWN":"不騙你，我現在壓力大到，一個不小心就會立刻暈過去的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 저 같은 일개 부사관 나부랭이에게 무슨 기대를 하는지 궁금합니다.","JPN":"でも、私みたいな一介の下士官に何を期待しているんでしょうか。","ENG":"But I'm curious to know what you expect from a lousy NCO like me.","TWN":"但我有點好奇，我不過就是一個小小的中士，你對我到底有什麼期待？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"카운터라도 해 봤자, 밖에 나가면 용병들이 득실거리는 이런 도시에선 아무 메리트 없잖아요?","JPN":"カウンターだとはいっても、一歩外に出れば傭兵が掃いて捨てるほどいるようなこんな都市では何のメリットもないじゃないですか？","ENG":"Even if I'm a Counter, it serves no merit in a city crawling with mercenaries, does it?","TWN":"就算我是制裁者，但外面到處都是傭兵，我也沒有比他們厲害吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"멋대로 배속 옮기라고 한 보안국도 그렇고, 다들 뭘 보고 나한테 이러나 따지고 싶을 정도라고요.","JPN":"勝手に配属移動をさせた保安局もそうだし、みんなどうして私に期待するのか問い詰めたいくらいです。","ENG":"With the National Security assigning me to wherever they want, I'm beginning to wonder what people see in me.","TWN":"隨便將我調職的安全局也是一樣，我不懂大家到底在我身上看到什麼，要這樣對我？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"전쟁터에 나가면 순 겁쟁이일 뿐인데…… 이깟 멋없는 쇳조각이 뭐라고.","JPN":"戦場に出ればただの怖がりなのに……こんな無粋な金属の塊が何だって言うんですかね。","ENG":"I'm nothing but a coward out on the battlefield... And this? It's just a tasteless hunk of metal.","TWN":"上戰場後我就只是個膽小鬼……這個廢鐵就根本不代表什麼！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"후우…. 그러니까, 그냥 평소처럼만 대해 주세요.","JPN":"ふう……つまり、いつもどおりに接してほしいってことです。","ENG":"Huu... So, just treat me like you normally would.","TWN":"哀…所以你就像平常那樣對待我就好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"저도 여기서 지낸 시간이 꽤나 쏠쏠했다는 건 부정 못하겠으니까요.","JPN":"私もここで過ごした時間がかなり良かったっていうのは認めます。","ENG":"Then I won't deny that my time here has been better than I expected.","TWN":"我不否認在這裡的時光還算愉快，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"우리나라에서 보낸 시간이 진짜 아무 의미 없었다고는 차마 말 못하겠지만요.","JPN":"わが国で過ごした時間が何の意味もなかったとは言えないですけどね。","ENG":"But I can't say that my time in my homeland was not really meaningful as well.","TWN":"但我也不好意思說在我的國家度過的時間都毫無意義。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"그럼 중사 크리스티나 브레히트. 앞으로도 사장님과 함께하겠습니다. 이상.","JPN":"では、軍曹クリスティーナ・ブレヒト、これからも社長と共にあります。以上。","ENG":"Then, I, Sergeant Christina Brecht, will continue to stay with you in the future, Boss. Over.","TWN":"總之克莉絲蒂娜·布萊希特中士，之後也決定要和老闆生死與共，以上！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};